designs.css:
.accord-wrapper {
  --accord-primary-color: #066e29; /* From original title */
  --accord-accent-color: #0afa2a; /* From original SVG */
  --accord-light-bg: #e2feee; /* From original image bg */
  --accord-button-green: #1aa06d; /* From original history button */
  --accord-text-main: #595b5f; /* From original message */
  --accord-text-alt: #242525; /* From original track button */
  --accord-border-light: #D1D5DB; /* From original dismiss border */
  --accord-bg-white: #fff;
  --accord-radius-main: 0.5rem; /* From original card radius */
  --accord-shadow-lg: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
  --accord-shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --accord-font-size-base: 16px;

  max-width: 600px; /* Wider than original card, suitable for accordion */
  margin: 2rem auto;
  background-color: var(--accord-bg-white);
  border-radius: var(--accord-radius-main);
  box-shadow: var(--accord-shadow-lg);
  overflow: hidden; /* Ensures border-radius is applied to children */
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen,
    Ubuntu, Cantarell, "Open Sans", "Helvetica Neue", sans-serif; /* A nice default font stack */
  font-size: var(--accord-font-size-base);
}

.accord-section {
  border-bottom: 1px solid var(--accord-border-light);
}

.accord-section:last-child {
  border-bottom: none; /* No border for the last item */
}

.accord-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 1.25rem;
  background-color: var(--accord-bg-white);
  color: var(--accord-primary-color);
  font-size: 1.1em; /* Relative to wrapper font size */
  font-weight: 600;
  cursor: pointer;
  list-style: none; /* Remove default marker */
  position: relative;
  transition: background-color 0.3s ease, color 0.3s ease, transform 0.2s ease, box-shadow 0.2s ease;
  user-select: none; /* Prevent text selection on click */
}

.accord-header:hover {
  background-color: var(--accord-light-bg); /* Lighter green on hover */
  color: var(--accord-button-green); /* Darker green for text */
  transform: translateY(-2px); /* Subtle lift */
  box-shadow: var(--accord-shadow-sm); /* Smaller shadow on hover */
}

/* Gradient effect for active/open header */
details[open] > .accord-header {
  background: linear-gradient(135deg, var(--accord-light-bg) 0%, #d8f5df 100%); /* Subtle green gradient */
  color: var(--accord-button-green);
  border-bottom: 1px solid transparent; /* No border when open, blends with content */
  box-shadow: none; /* Remove hover shadow if active */
  transform: none; /* Reset lift if active */
}

.accord-title {
  font-size: 1em; /* Relative to accord-header font size */
  margin: 0; /* Remove default h3 margin */
}

/* Custom indicator icon */
.accord-indicator {
  position: relative;
  width: 1em; /* Adjust size */
  height: 1em;
  flex-shrink: 0;
  color: var(--accord-primary-color); /* Color of the plus/minus sign */
}

.accord-indicator::before,
.accord-indicator::after {
  content: '';
  position: absolute;
  background-color: currentColor; /* Use currentColor to inherit from parent */
  transition: transform 0.3s ease, opacity 0.3s ease;
  left: 50%;
  top: 50%;
}

.accord-indicator::before { /* Vertical line */
  width: 2px;
  height: 100%;
  transform: translate(-50%, -50%);
}

.accord-indicator::after { /* Horizontal line */
  width: 100%;
  height: 2px;
  transform: translate(-50%, -50%);
}

details[open] > .accord-header .accord-indicator::before {
  transform: translate(-50%, -50%) rotate(90deg); /* Rotate vertical line to become horizontal */
}

details[open] > .accord-header .accord-indicator::after {
  transform: translate(-50%, -50%) scaleX(0); /* Make horizontal line disappear for a cleaner single-line dash */
  opacity: 0;
}

.accord-content {
  padding: 0 1.25rem;
  background-color: var(--accord-bg-white);
  color: var(--accord-text-main);
  line-height: 1.6;
  max-height: 0; /* Start collapsed */
  overflow: hidden;
  transition: max-height 0.4s ease-out, opacity 0.4s ease-out, padding 0.4s ease-out;
  opacity: 0;
}

.accord-content .accord-text {
  margin-bottom: 1rem;
}

.accord-content .accord-text:last-child {
  margin-bottom: 0;
}

details[open] > .accord-content {
  max-height: 500px; /* A sufficiently large value for max-height */
  opacity: 1;
  padding: 1rem 1.25rem 1.25rem; /* Adjust padding for open state */
}

/* Subtle animation on content text */
@keyframes slideInUp {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

details[open] > .accord-content .accord-text {
  animation: slideInUp 0.4s ease-out forwards;
}

/* Stagger animation for multiple paragraphs */
details[open] > .accord-content .accord-text:nth-child(1) { animation-delay: 0s; }
details[open] > .accord-content .accord-text:nth-child(2) { animation-delay: 0.1s; }
details[open] > .accord-content .accord-text:nth-child(3) { animation-delay: 0.2s; }
details[open] > .accord-content .accord-text:nth-child(4) { animation-delay: 0.3s; }
